import { useEffect, useState } from "react";
import SongBlock from "./SongBlock";
import styles from "./SongsCard.module.css";

export default function SongsCard({ songInfo }) {
    const [tracks, setTracks] = useState([]);

    useEffect(() => {
        if (!songInfo) return;

        const fetchTracks = async () => {
            const requests = songInfo.map(async (song) => {
                const spotifyLink =
                    song.properties["Spotify Link"]?.url;

                if (!spotifyLink) return null;

                const response = await fetch(
                    `/api/spotify-track?url=${encodeURIComponent(
                        spotifyLink
                    )}`
                );

                if (!response.ok) return null;

                return response.json();
            });

            const results = await Promise.all(requests);
            setTracks(results.filter(Boolean));
        };

        fetchTracks();
    }, [songInfo]);

    if (tracks.length === 0) return null;

    const featuredTrack = tracks[0];
    const secondaryTracks = tracks.slice(1);

    return (
        <section className={styles.wrapper}>
            <h1>Currently Listening</h1>

            <div className={styles.layout}>
                <div className={styles.secondarySongs}>
                    {secondaryTracks.map((track) => (
                        <SongBlock
                            key={track.spotifyUrl}
                            track={track}
                        />
                    ))}
                </div>

                <SongBlock
                    track={featuredTrack}
                    featured
                />
            </div>
        </section>
    );
}